steps.body:
localStorage só guarda string.

Se você quer guardar um objeto:

const usuario = { nome: 'Bruno', pontos: 10 };
localStorage.setItem('usuario', JSON.stringify(usuario));

Para ler:
const texto = localStorage.getItem('usuario');
const usuarioLido = JSON.parse(texto);

Se você não usar JSON:
- você perde estrutura
- vira uma bagunça de strings

extra.modelJs:
/* Aula 17 — modelJs: JSON + localStorage */

// 1) Objeto normal
const config = { tema: 'dark', fonte: 16, animacoes: false };

// 2) Objeto -> JSON (texto)
const configJsonBonito = JSON.stringify(config, null, 2);
console.log('JSON bonito:\n', configJsonBonito);

// 3) Salvar no localStorage (string)
localStorage.setItem('config', configJsonBonito);

// 4) Ler e converter de volta
const textoLido = localStorage.getItem('config');
console.log('textoLido:', textoLido);

const configLida = JSON.parse(textoLido);
console.log('configLida:', configLida);
console.log('tema:', configLida.tema);

// 5) Parse com erro (try/catch)
try {
  JSON.parse('{ ok: true }');
} catch (err) {
  console.error('Parse falhou:', err.message);
}
